#include <stdio.h>
#include <stdbool.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        long long sum = 0; bool hasTwo = false;
        for(int i=0;i<N;i++){
            long long x; scanf("%lld", &x);
            sum += x;
            if(x==2) hasTwo = true;
        }
        if(sum%2==0) printf("0\n");
        else if(hasTwo) printf("1\n");
        else printf("-1\n");
    }
    return 0;
}

