code.Java:
import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            StringTokenizer st = new StringTokenizer(br.readLine());
            long sum = 0;
            boolean hasTwo = false;
            for (int i = 0; i < N; i++) {
                long x = Long.parseLong(st.nextToken());
                sum += x;
                if (x == 2) hasTwo = true;
            }
            if ((sum & 1) == 0) out.append(0).append('\n');
            else if (hasTwo) out.append(1).append('\n');
            else out.append(-1).append('\n');
        }
        System.out.print(out.toString());
    }
}

code.Python3:
#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        sum_val = 0
        has_two = False
        for _ in range(N):
            x = int(next(it))
            sum_val += x
            if x == 2:
                has_two = True
        if sum_val % 2 == 0:
            out_lines.append('0')
        elif has_two:
            out_lines.append('1')
        else:
            out_lines.append('-1')
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

